SELECT COUNT(*) AS active_metrics_count
FROM component_metrics
WHERE is_active = 1;

SELECT metric_id, AVG(value) AS average_value
FROM metrics_values
WHERE metric_id = 1;

SELECT category_name, description 
FROM metrics_categories 
WHERE is_active = 1;

SELECT metric_id, AVG(threshold_value) AS average_threshold, COUNT(*) AS number_of_thresholds
FROM thresholds
GROUP BY metric_id;

SELECT AVG(value) AS average_value
FROM metrics_values
WHERE metric_id = 1;

SELECT MAX(value) AS max_value, metric_id, component_id, value_type
FROM metrics_values
GROUP BY metric_id, component_id, value_type;

SELECT metric_id, value_type
FROM metrics_values
WHERE metric_id = 0;
